'use client';

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { FinancialTransactionWithDetails } from '@/types/financial';
import { Button } from '@/components/ui/button';
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { useFinancialTransactions } from '@/hooks/useFinancialTransactions';
import { useFinancialAccounts } from '@/hooks/useFinancialAccounts';
import { useFinancialCategories } from '@/hooks/useFinancialCategories';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { useState } from 'react';
import { Plus } from 'lucide-react';
import { Textarea } from '@/components/ui/textarea';

const formSchema = z.object({
    description: z.string().min(2, { message: 'Descrição necessária.' }),
    amount: z.coerce.number().positive({ message: 'Valor deve ser positivo.' }),
    type: z.enum(['entrada', 'saida']),
    category_id: z.string().min(1, 'Categoria obrigatória'),
    account_id: z.string().min(1, 'Conta obrigatória'),
    date: z.string(), // ISO date string
    notes: z.string().optional(),
});

export function TransactionForm({
    transactionToEdit,
    onSuccess,
    open: externalOpen,
    onOpenChange: externalOnOpenChange,
    defaultType = 'saida'
}: {
    transactionToEdit?: FinancialTransactionWithDetails | null;
    onSuccess?: () => void;
    open?: boolean;
    onOpenChange?: (open: boolean) => void;
    defaultType?: 'entrada' | 'saida';
}) {
    const [internalOpen, setInternalOpen] = useState(false);

    // Controlled or uncontrolled open state
    const open = externalOpen !== undefined ? externalOpen : internalOpen;
    const setOpen = externalOnOpenChange || setInternalOpen;

    const { createTransaction, updateTransaction } = useFinancialTransactions();
    const { accounts } = useFinancialAccounts();
    const { categories } = useFinancialCategories();

    // Reset form when transactionToEdit changes is complicated with useForm defaultValues
    // Better to rely on the key prop in the parent or useEffect to reset
    const form = useForm<z.infer<typeof formSchema>>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            description: transactionToEdit?.description || '',
            amount: transactionToEdit?.amount || 0,
            type: (transactionToEdit?.type as 'entrada' | 'saida') || defaultType,
            category_id: transactionToEdit?.category_id || '',
            account_id: transactionToEdit?.account_id || '',
            date: transactionToEdit?.transaction_date ? transactionToEdit.transaction_date.split('T')[0] : new Date().toISOString().split('T')[0],
            notes: transactionToEdit?.notes || '',
        },
    });

    const transactionType = form.watch('type');
    const filteredCategories = categories.filter(c => c.type === transactionType);

    const onSubmit = async (values: z.infer<typeof formSchema>) => {
        try {
            if (transactionToEdit) {
                await updateTransaction.mutateAsync({
                    id: transactionToEdit.id,
                    updates: {
                        description: values.description,
                        amount: values.amount,
                        type: values.type,
                        category_id: values.category_id,
                        account_id: values.account_id,
                        transaction_date: values.date,
                        notes: values.notes,
                    }
                });
            } else {
                await createTransaction.mutateAsync({
                    description: values.description,
                    amount: values.amount,
                    type: values.type,
                    category_id: values.category_id,
                    account_id: values.account_id,
                    transaction_date: values.date, // Fixed property name from date to transaction_date
                    status: 'concluida',
                    payment_method: 'outros',
                    notes: values.notes,
                });
            }
            setOpen(false);
            form.reset();
            if (onSuccess) onSuccess();
        } catch (error) {
            console.error(error);
        }
    };

    const isPending = createTransaction.isPending || updateTransaction.isPending;

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            {!externalOnOpenChange && (
                <DialogTrigger asChild>
                    <Button>
                        <Plus className="mr-2 h-4 w-4" /> Nova Transação
                    </Button>
                </DialogTrigger>
            )}
            <DialogContent className="sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle>{transactionToEdit ? 'Editar Transação' : 'Nova Transação'}</DialogTitle>
                </DialogHeader>
                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <FormField
                                control={form.control}
                                name="type"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Tipo</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="entrada">Receita</SelectItem>
                                                <SelectItem value="saida">Despesa</SelectItem>
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="date"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Data</FormLabel>
                                        <FormControl>
                                            <Input type="date" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                        </div>

                        <FormField
                            control={form.control}
                            name="description"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Descrição</FormLabel>
                                    <FormControl>
                                        <Input placeholder="Ex: Pagamento Fornecedor" {...field} />
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <div className="grid grid-cols-2 gap-4">
                            <FormField
                                control={form.control}
                                name="amount"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Valor (R$)</FormLabel>
                                        <FormControl>
                                            <Input type="number" step="0.01" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="account_id"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Conta</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Selecione..." />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                {accounts.map((acc) => (
                                                    <SelectItem key={acc.id} value={acc.id}>{acc.name}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                        </div>

                        <FormField
                            control={form.control}
                            name="category_id"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Categoria</FormLabel>
                                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                                        <FormControl>
                                            <SelectTrigger>
                                                <SelectValue placeholder="Selecione uma categoria" />
                                            </SelectTrigger>
                                        </FormControl>
                                        <SelectContent>
                                            {filteredCategories.map((cat) => (
                                                <SelectItem key={cat.id} value={cat.id}>{cat.name}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <FormField
                            control={form.control}
                            name="notes"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Observações</FormLabel>
                                    <FormControl>
                                        <Textarea placeholder="Detalhes adicionais..." {...field} />
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <div className="flex justify-end pt-4">
                            <Button type="submit" disabled={isPending}>
                                {isPending ? 'Salvando...' : (transactionToEdit ? 'Atualizar Transação' : 'Salvar Transação')}
                            </Button>
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
}
