'use client'

import { useState } from "react"
import { FinancialTransactionWithDetails, TransactionType, TransactionStatus } from "@/types/financial"
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import {
    ArrowUpRight,
    ArrowDownLeft,
    Search,
    MoreHorizontal,
    Eye,
    Edit,
    Trash2,
    Filter,
    Download,
    Loader2
} from "lucide-react"
import { formatCurrency, formatDate } from "@/lib/utils"
import { TransactionForm } from "./TransactionForm"
import { useFinancialTransactions } from "@/hooks/useFinancialTransactions"

interface TransactionsTableProps {
    initialData?: FinancialTransactionWithDetails[];
    defaultFilterType?: "all" | "entrada" | "saida";
    lockFilterType?: boolean;
}

export function TransactionsTable({
    initialData = [],
    defaultFilterType = "all",
    lockFilterType = false
}: TransactionsTableProps) {
    const { deleteTransaction, isLoading: isHookLoading } = useFinancialTransactions()
    const [searchTerm, setSearchTerm] = useState("")
    const [filterType, setFilterType] = useState<"all" | "entrada" | "saida">(defaultFilterType)
    const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null)
    const [editingTransaction, setEditingTransaction] = useState<FinancialTransactionWithDetails | null>(null)
    const [isEditModalOpen, setIsEditModalOpen] = useState(false)

    // Filter
    // Note: In a real world scenario with large datasets, filtering should be server-side or via hook options.
    // For now, valid for the passed initialData list.
    const filteredData = initialData.filter(transaction => {
        const matchesSearch =
            transaction.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
            transaction.category?.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            transaction.account?.name.toLowerCase().includes(searchTerm.toLowerCase())

        const matchesType = filterType === "all" || transaction.type === filterType

        return matchesSearch && matchesType
    })

    const handleEdit = (transaction: FinancialTransactionWithDetails) => {
        setEditingTransaction(transaction)
        setIsEditModalOpen(true)
    }

    const handleDeleteClick = (id: string) => {
        setTransactionToDelete(id)
    }

    const handleConfirmDelete = async () => {
        if (transactionToDelete) {
            await deleteTransaction.mutateAsync(transactionToDelete)
            setTransactionToDelete(null)
            // Ideally, we should also trigger a refresh of initialData or invalidation,
            // which the hook's onSuccess handles (invalidates queries).
            // However, since this component relies on 'initialData' passed from parent,
            // the parent needs to re-fetch or we should rely on the hook's 'transactions' data if we want live updates.
            // For now, assuming the parent or React Query invalidation will handle the UI update if this component 
            // was using the hook for data fetching.
            // Since it uses props, the page might need a refresh unless we switch to hook-based data.
        }
    }

    return (
        <div className="space-y-4">
            {/* Filters */}
            <div className="flex flex-col sm:flex-row gap-4 justify-between">
                <div className="flex gap-2 flex-1">
                    <div className="relative flex-1 max-w-sm">
                        <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar transações..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-8"
                        />
                    </div>
                    {!lockFilterType && (
                        <div className="flex rounded-md shadow-sm">
                            <Button
                                variant={filterType === "all" ? "default" : "outline"}
                                className="rounded-r-none"
                                size="sm"
                                onClick={() => setFilterType("all")}
                            >
                                Todas
                            </Button>
                            <Button
                                variant={filterType === "entrada" ? "default" : "outline"}
                                className="rounded-none border-l-0"
                                size="sm"
                                onClick={() => setFilterType("entrada")}
                            >
                                Receitas
                            </Button>
                            <Button
                                variant={filterType === "saida" ? "default" : "outline"}
                                className="rounded-l-none border-l-0"
                                size="sm"
                                onClick={() => setFilterType("saida")}
                            >
                                Despesas
                            </Button>
                        </div>
                    )}
                </div>
            </div>

            {/* Table */}
            <div className="rounded-md border">
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Data</TableHead>
                            <TableHead>Descrição</TableHead>
                            <TableHead>Categoria</TableHead>
                            <TableHead>Conta</TableHead>
                            <TableHead className="text-right">Valor</TableHead>
                            <TableHead className="text-center">Status</TableHead>
                            <TableHead className="w-[50px]"></TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredData.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={7} className="h-24 text-center">
                                    Nenhuma transação encontrada.
                                </TableCell>
                            </TableRow>
                        ) : (
                            filteredData.map((transaction) => (
                                <TableRow key={transaction.id}>
                                    <TableCell className="font-medium">
                                        {formatDate(transaction.transaction_date)}
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex flex-col">
                                            <span className="font-medium">{transaction.description}</span>
                                            {transaction.contact && (
                                                <span className="text-xs text-muted-foreground">{transaction.contact.full_name}</span>
                                            )}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant="secondary" className="font-normal" style={{
                                            backgroundColor: transaction.category?.color ? `${transaction.category.color}20` : undefined,
                                            color: transaction.category?.color || undefined
                                        }}>
                                            {transaction.category?.name || 'Sem categoria'}
                                        </Badge>
                                    </TableCell>
                                    <TableCell>
                                        <span className="text-sm text-muted-foreground">{transaction.account?.name}</span>
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <div className={`font-bold flex items-center justify-end gap-1 ${transaction.type === 'entrada' ? 'text-emerald-600' : 'text-red-600'
                                            }`}>
                                            {transaction.type === 'entrada' ? <ArrowUpRight className="h-3 w-3" /> : <ArrowDownLeft className="h-3 w-3" />}
                                            {formatCurrency(transaction.amount)}
                                        </div>
                                    </TableCell>
                                    <TableCell className="text-center">
                                        <Badge variant={transaction.status === 'concluida' ? 'default' : 'secondary'}>
                                            {transaction.status}
                                        </Badge>
                                    </TableCell>
                                    <TableCell>
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button variant="ghost" className="h-8 w-8 p-0">
                                                    <span className="sr-only">Abrir menu</span>
                                                    <MoreHorizontal className="h-4 w-4" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end">
                                                <DropdownMenuItem onClick={() => console.log('View', transaction)}>
                                                    <Eye className="mr-2 h-4 w-4" /> Detalhes
                                                </DropdownMenuItem>
                                                <DropdownMenuItem onClick={() => handleEdit(transaction)}>
                                                    <Edit className="mr-2 h-4 w-4" /> Editar
                                                </DropdownMenuItem>
                                                <DropdownMenuItem
                                                    className="text-red-600 focus:text-red-600"
                                                    onClick={() => handleDeleteClick(transaction.id)}
                                                >
                                                    <Trash2 className="mr-2 h-4 w-4" /> Excluir
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>

            <AlertDialog open={!!transactionToDelete} onOpenChange={(open) => !open && setTransactionToDelete(null)}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Excluir transação?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Esta ação não pode ser desfeita. A transação será removida e o saldo da conta será atualizado.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancelar</AlertDialogCancel>
                        <AlertDialogAction
                            className="bg-red-500 hover:bg-red-600"
                            onClick={handleConfirmDelete}
                            disabled={deleteTransaction.isPending}
                        >
                            {deleteTransaction.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Excluir
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>

            <TransactionForm
                open={isEditModalOpen}
                onOpenChange={setIsEditModalOpen}
                transactionToEdit={editingTransaction}
                onSuccess={() => {
                    setIsEditModalOpen(false)
                    setEditingTransaction(null)
                    // Optional: trigger data refresh if needed
                }}
            />
        </div>
    )
}
